const body = (typeof $json.body === 'object' && $json.body !== null) ? $json.body : $json;

function normalizeWebsiteId(value) {
  const raw = String(value || '').trim();
  if (!raw) return 'test-website-com';

  return raw
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .replace(/[#?].*$/, '')
    .replace(/[^a-z0-9]+/gi, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .toLowerCase();
}

const websiteUrl = body.website_id || body.url || body.websiteId || '';
const website_id = normalizeWebsiteId(websiteUrl);

return [{
  json: {
    website_id,
    question: body.question || 'Test question'
  }
}];
